#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <cmath>
#include <iomanip>
#include <algorithm>

// Forward declaration of the function containing the quadratic solver logic
void solve_quadratic_equation(std::istream& in, std::ostream& out);

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        {"1 -5 6", "Enter coefficients a, b, and c: Roots are real and distinct. Root 1 = 3.00, Root 2 = 2.00"},
        {"1 -4 4", "Enter coefficients a, b, and c: Roots are real and equal. Root 1 = 2.00, Root 2 = 2.00"},
        {"1 1 1", "Enter coefficients a, b, and c: Roots are complex. Root 1 = -0.50 + 0.87i, Root 2 = -0.50 - 0.87i"},
        {"0 2 4", "Enter coefficients a, b, and c: Coefficient 'a' is zero. This is a linear equation. Root = -2.00"},
        {"0 0 5", "Enter coefficients a, b, and c: Coefficient 'a' is zero. This is a linear equation. No real root."},
        {"0 0 0", "Enter coefficients a, b, and c: Coefficient 'a' is zero. This is a linear equation. Infinite solutions."}
    };

    std::streambuf* original_cin_buf = std::cin.rdbuf();
    std::streambuf* original_cout_buf = std::cout.rdbuf();

    bool all_passed = true;

    for (size_t i = 0; i < test_cases.size(); ++i) {
        std::string input = test_cases[i].first;
        std::string expected_output = test_cases[i].second;

        std::istringstream iss(input);
        std::ostringstream oss;

        std::cin.rdbuf(iss.rdbuf());
        std::cout.rdbuf(oss.rdbuf());

        solve_quadratic_equation(std::cin, std::cout);

        std::string actual_output = oss.str();

        if (!actual_output.empty() && actual_output.back() == '\n') {
            actual_output.pop_back();
        }
        if (!expected_output.empty() && expected_output.back() == '\n') {
            expected_output.pop_back();
        }

        if (actual_output != expected_output) {
            std::cerr << "Test Case " << i + 1 << " Failed!\n";
            std::cerr << "Input: \"" << input << "\"\n";
            std::cerr << "Expected: \"" << expected_output << "\"\n";
            std::cerr << "Actual: \"" << actual_output << "\"\n";
            all_passed = false;
        } 
    }

    std::cin.rdbuf(original_cin_buf);
    std::cout.rdbuf(original_cout_buf);

    if (!all_passed) {
        return 1;
    }
    return 0;
}
